def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0.0
        if ratio > 2:
            for p in range(1, 5):
                temp = (ratio ** (2 * p)) / (p + 1)
                if p % 2 == 0:
                    score += temp * np.sin(p * np.pi / 2)
                else:
                    score -= temp * np.cos(p * np.pi / 3)
            priorities[i] = score + (ratio ** 2.5)
        elif 1 < ratio <= 2:
            penalty = 0
            for k in range(1, 6):
                penalty += ((ratio - 1) ** k) / (k ** 2)
            priorities[i] = (ratio ** 3) + penalty
        elif 0.5 < ratio <= 1:
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                term = sign * (ratio ** j) / (j + 0.5)
                score += term
            multiplier = 20 if ratio < 0.75 else 12 if ratio < 0.95 else 8
            extra = 0
            for m in range(1, 5):
                if m % 2 == 1:
                    extra += (ratio ** (m * 1.5)) / (m + 2)
                else:
                    extra -= (ratio ** m) / (m + 3)
            priorities[i] = abs(score) * multiplier + extra
        elif 0 < ratio <= 0.5:
            partial = 0
            for n in range(1, 10):
                if n % 4 == 0:
                    partial += (ratio ** (n/2)) / (n + 1)
                else:
                    partial -= (ratio ** n) / (n + 2)
            priorities[i] = abs(partial) * 25
        else:
            priorities[i] = np.inf
    for idx in range(len(priorities)):
        if priorities[idx] != np.inf and bins[idx] - item < item * 0.1 and bins[idx] > 0:
            priorities[idx] *= 0.5
    return priorities
